import { describe, expect, it } from "vitest";
import fs from "node:fs";
import path from "node:path";

const QUESTION_DIR = path.resolve(
  __dirname,
  "../../public/questions/toefl/reading/complete-words",
);

interface CompleteWordsItem {
  index: number;
  hint: string;
  answer: string;
}

interface CompleteWordsData {
  paragraph: string;
  items: CompleteWordsItem[];
}

function getQuestionFiles(): string[] {
  return fs
    .readdirSync(QUESTION_DIR)
    .filter((f) => f.endsWith(".json") && f !== "index.json")
    .sort();
}

function loadJson(file: string): CompleteWordsData {
  const raw = fs.readFileSync(path.join(QUESTION_DIR, file), "utf-8");
  return JSON.parse(raw) as CompleteWordsData;
}

describe("TOEFL Reading: Complete the Words JSON structure", () => {
  const files = getQuestionFiles();

  it("has files", () => {
    expect(files.length).toBeGreaterThan(0);
  });

  it.each(files)("%s is valid JSON", (file) => {
    expect(() => loadJson(file)).not.toThrow();
  });

  it.each(files)("%s has paragraph and items fields", (file) => {
    const data = loadJson(file);
    expect(data).toHaveProperty("paragraph");
    expect(typeof data.paragraph).toBe("string");
    expect(data.paragraph.trim()).not.toBe("");
    expect(data).toHaveProperty("items");
    expect(Array.isArray(data.items)).toBe(true);
  });

  // Word count: 70-100
  it.each(files)("%s paragraph is 70〜100 words", (file) => {
    const data = loadJson(file);
    const wc = data.paragraph.split(/\s+/).filter(Boolean).length;
    expect(wc).toBeGreaterThanOrEqual(70);
    expect(wc).toBeLessThanOrEqual(100);
  });

  // Items: exactly 10
  it.each(files)("%s has exactly 10 items", (file) => {
    const data = loadJson(file);
    expect(data.items.length).toBe(10);
  });

  // Items in order, hint 2-3 chars, hint matches start of answer
  it.each(files)("%s items have valid structure", (file) => {
    const data = loadJson(file);
    const words = data.paragraph.split(/\s+/).filter(Boolean);
    let prevWordIdx = -10;

    for (let i = 0; i < data.items.length; i++) {
      const item = data.items[i];

      // index must match position
      expect(item.index).toBe(i);

      // hint must be 2-3 chars
      expect(item.hint.length).toBeGreaterThanOrEqual(2);
      expect(item.hint.length).toBeLessThanOrEqual(3);

      // hint must match start of answer (case-insensitive)
      expect(item.answer.toLowerCase()).toMatch(
        new RegExp(`^${item.hint.toLowerCase()}`),
      );

      // answer must exist in paragraph
      const foundIdx = words.findIndex(
        (w, idx) =>
          w.replace(/[.,;:!?'"()[\]]/g, "").toLowerCase() ===
            item.answer.toLowerCase() && idx > prevWordIdx,
      );
      expect(foundIdx).not.toBe(-1);

      // at least 3 words gap
      expect(foundIdx - prevWordIdx).toBeGreaterThanOrEqual(3);

      prevWordIdx = foundIdx;
    }
  });
});

import { describe, expect, it } from "vitest";
import fs from "node:fs";
import path from "node:path";

const QUESTION_DIR = path.resolve(
  __dirname,
  "../../public/questions/toefl/reading/academic",
);

const VALID_QUESTION_TYPES = [
  "vocabulary",
  "detail",
  "inference",
  "mainIdea",
  "paragraphRelation",
  "importantIdea",
  "negativeFactual",
  "rhetoricalPurpose",
  "insertSentence",
];

interface AcademicQuestion {
  id: string;
  type: string;
  stem: string;
  options: string[];
  correctIndex: number;
  explanation: string;
}

interface AcademicData {
  title: string;
  passage: string;
  questions: AcademicQuestion[];
}

function getQuestionFiles(): string[] {
  return fs
    .readdirSync(QUESTION_DIR)
    .filter((f) => f.endsWith(".json") && f !== "index.json")
    .sort();
}

function loadJson(file: string): AcademicData {
  const raw = fs.readFileSync(path.join(QUESTION_DIR, file), "utf-8");
  return JSON.parse(raw) as AcademicData;
}

describe("TOEFL Reading: Academic Passage JSON structure", () => {
  const files = getQuestionFiles();

  it("has at least one question file", () => {
    expect(files.length).toBeGreaterThan(0);
  });

  it.each(files)("%s is valid JSON", (file) => {
    expect(() => loadJson(file)).not.toThrow();
  });

  it.each(files)("%s has required top-level fields", (file) => {
    const data = loadJson(file);
    expect(data).toHaveProperty("title");
    expect(typeof data.title).toBe("string");
    expect(data.title.trim()).not.toBe("");

    expect(data).toHaveProperty("passage");
    expect(typeof data.passage).toBe("string");
    expect(data.passage.trim()).not.toBe("");

    expect(data).toHaveProperty("questions");
    expect(Array.isArray(data.questions)).toBe(true);
  });

  // Word count: 150-250 (spec says 150-250, but existing 001-007 exceed; new files must comply)
  it.each(files)("%s passage is 150〜250 words (spec: 目安200)", (file) => {
    const data = loadJson(file);
    const wc = data.passage.split(/\s+/).filter(Boolean).length;
    expect(wc).toBeGreaterThanOrEqual(150);
    expect(wc).toBeLessThanOrEqual(250);
  });

  // Questions: exactly 5
  it.each(files)("%s has 5 questions", (file) => {
    const data = loadJson(file);
    expect(data.questions.length).toBe(5);
  });

  it.each(files)("%s questions have required fields", (file) => {
    const data = loadJson(file);
    const seenIds = new Set<string>();

    for (const q of data.questions) {
      expect(q).toHaveProperty("id");
      expect(typeof q.id).toBe("string");
      expect(q.id.trim()).not.toBe("");
      expect(seenIds.has(q.id)).toBe(false);
      seenIds.add(q.id);

      expect(q).toHaveProperty("type");
      expect(VALID_QUESTION_TYPES).toContain(q.type);

      expect(q).toHaveProperty("stem");
      expect(typeof q.stem).toBe("string");
      expect(q.stem.trim()).not.toBe("");

      expect(q).toHaveProperty("options");
      expect(Array.isArray(q.options)).toBe(true);
      expect(q.options.length).toBe(4);
      for (const opt of q.options) {
        expect(typeof opt).toBe("string");
        expect(opt.trim()).not.toBe("");
      }

      expect(q).toHaveProperty("correctIndex");
      expect(typeof q.correctIndex).toBe("number");
      expect(q.correctIndex).toBeGreaterThanOrEqual(0);
      expect(q.correctIndex).toBeLessThanOrEqual(3);

      expect(q).toHaveProperty("explanation");
      expect(typeof q.explanation).toBe("string");
      expect(q.explanation.trim()).not.toBe("");
    }
  });

  // Question type distribution: at least 3 distinct types per file
  it.each(files)("%s uses at least 3 different question types", (file) => {
    const data = loadJson(file);
    const types = new Set(data.questions.map((q) => q.type));
    expect(types.size).toBeGreaterThanOrEqual(3);
  });

  // Every type appears somewhere
  it("all valid question types appear across files", () => {
    const allTypes = new Set<string>();
    for (const file of files) {
      const data = loadJson(file);
      for (const q of data.questions) {
        allTypes.add(q.type);
      }
    }
    for (const t of VALID_QUESTION_TYPES) {
      expect(allTypes).toContain(t);
    }
  });
});

