  stem: string;
  options: string[];
  correctIndex: number;
  type: string;
  explanation: string;
}

interface AudioSegment {
  role: string;
  text: string;
}

interface ConversationData {
  title: string;
  transcript: string;
  questions: ConversationQuestion[];
